#include <iostream>
#include <unordered_set>

using namespace std;

int main()
{
    unordered_set<int> numbers;
    numbers.insert(30);
    numbers.insert(10);
    numbers.insert(20);
    numbers.insert(10); // duplicate — still silently ignored

    cout << numbers.count(20) << endl;
    cout << numbers.size() << endl;

    return 0;
}

